// Demonstrating Promise.race() - executes the first Promise to resolve/reject.
const promise1 = new Promise((resolve, reject) => setTimeout(() => resolve("Promise 1 resolved!"), 1000));
const promise2 = new Promise((resolve, reject) => setTimeout(() => reject("Promise 2 rejected!"), 500));

Promise.race([promise1, promise2])
  .then(result => {
    console.log("The first promise to complete was:", result); // Will log "Promise 2 rejected!"
  })
  .catch(error => {
    console.error("All promises rejected:", error);
  });

// Explanation:
// Promise.race() is ideal when you want to quickly determine the outcome of multiple asynchronous operations, 
